module RefModule(
  input clk,
  input rst_n,
  output reg clk_out
);

  reg [1:0] unused_counter;

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      unused_counter <= 2'b00;
      clk_out <= 1'b0;
    end else begin
      if (unused_counter == 2'b11) begin
        unused_counter <= 2'b00;
        clk_out <= ~clk_out;
      end else begin
        unused_counter <= unused_counter + 1;
      end
    end
  end

endmodule
